  }, { root: null, threshold: [0.25, 0.5, 0.75], rootMargin: '0px 0px -40% 0px' });

  document.querySelectorAll('section[id]').forEach(sec => io.observe(sec));

  /* =========================
     VIDEO-CARD: PLAY HANDLER
  ========================== */
  window.playVideo = function (card) {
