}
/* Keyframes for gradient animation   codex edit_integriert */
@keyframes gradient {
  0% { background-position: 0% 50%; }
  50% { background-position: 100% 50%; }
  100% { background-position: 0% 50%; }
}
/* Class to apply gradient animation */
.animate-gradient {
  background-size: 200% 200%;
  animation: gradient 15s ease infinite;
}
/* Carousel base styles */
.carousel-container {
  scroll-snap-type: x mandatory;
  scrollbar-width: none; /* Firefox */
  -ms-overflow-style: none; /* IE and Edge */
  scroll-behavior: smooth;
  overflow-y: hidden;
  overscroll-behavior-x: contain;
  overscroll-behavior-y: none;
  touch-action: pan-x;
  -webkit-overflow-scrolling: touch;
}
/* Hide scrollbar for Webkit browsers */
.carousel-container::-webkit-scrollbar {
  display: none;
}
/* Carousel item snap alignment */
.carousel-item {
  scroll-snap-align: start;
  scroll-snap-stop: always;
}

.carousel-container:focus-visible {
  outline: 2px solid #2563eb;
  outline-offset: 2px;
}

.carousel-container.is-dragging {
  cursor: grabbing;
  scroll-behavior: auto;
}

.carousel-container .carousel-item img,
.carousel-container .carousel-item video {
  user-select: none;
  -webkit-user-drag: none;
}

#carousel1 .carousel-item {
  overflow: hidden;
}

#carousel1 [data-parallax-media] {
  will-change: transform;
  transform: scale(1.08);
  transition: transform 220ms linear;
}

