    padding:0 14px;
    border-radius:14px;
  }
}

/* Teilprojekt 3.1: Basis */
.k3-wrap.k3-wrap{
  width:100%;
  max-width:1440px;
  margin:70px auto;
  padding:0 24px;
}

.k3-wrap .k3-roof{
