    grid-template-columns: 1.15fr 0.85fr;
    gap:56px;
    margin-bottom:26px;
  }
}

/* 3.1 Titel: nicht abschneiden */
.k3-wrap .k3-title{
  font-weight:900;
  letter-spacing:-0.05em;
  line-height:0.92;
  color:#26313f;
  margin:14px 0 18px;
