  white-space:normal;
  overflow-wrap:anywhere;
}

@media (max-width: 520px){
  .k3-wrap .k3-title{
    font-size:clamp(2.0rem, 9vw, 3.2rem);
  }
}

.k3-wrap .k3-lead{
  color:rgba(61,70,84,0.78);
  font-size:clamp(1.05rem,1.25vw,1.25rem);
  line-height:1.65;
  max-width:62ch;
}

/* Dachbild rechts: nicht abschneiden */
.k3-wrap .k3-hero{
  height:min(420px,48vh);
  background:transparent;
  border:0;
  border-radius:12px;
  overflow:visible;
  box-shadow:none;
  display:flex;
  align-items:center;
  justify-content:center;
}

.k3-wrap .k3-hero img{
  width:100%;
  height:100%;
  display:block;
  object-fit:contain;
  object-position:center;
  transform:none;
  filter:none !important;
  opacity:1 !important;
  mix-blend-mode:normal !important;
}

/* Slider Shell: Hintergrund komplett weg */
.k3-wrap .k3-shell{
  position:relative;
  margin-top:16px;
  padding:18px 0 26px;
  background:transparent;
  overflow:visible;
}

.k3-wrap .k3-parallax,
.k3-wrap .k3-grain{
  display:none !important;
}

/* Track: scrollt, aber ohne Scrollbar */
.k3-wrap .k3-track{
  display:flex;
  gap:22px;
  overflow-x:auto;
  overflow-y:hidden;
  padding:10px 0 8px;
  scroll-snap-type:x mandatory;
  scroll-padding: 12vw;
  -webkit-overflow-scrolling:touch;
  overscroll-behavior-x:contain;
  overscroll-behavior-y:none;
  touch-action:pan-x;
  cursor:grab;

  scrollbar-width:none;
  -ms-overflow-style:none;
  position:relative;
  z-index:2;
}

.k3-wrap .k3-track::-webkit-scrollbar{ display:none; }

.k3-wrap .k3-track:focus-visible{
  outline:2px solid #2563eb;
  outline-offset:4px;
}

.k3-wrap .k3-track.is-dragging{
