}

.panel-cta-button{
  padding: 16px 38px !important;
  min-height: 56px;
  font-size: 14px !important;
  background: linear-gradient(160deg, #ffffff, #f0f8ff) !important;
  color: #0f172a !important;
  border: 1px solid rgba(37,99,235,0.24) !important;
  box-shadow: 0 18px 40px rgba(59,130,246,0.2) !important;
}

/* 8) CTA-Person größer und an Unterkante angedockt */
.cta-figure-img{
  bottom: 0 !important;
  top: auto !important;
  right: -14px !important;
  width: min(430px, 48vw) !important;
}

/* 9) Mehr vertikale Abstände zwischen Sections */
.case-grid{
  gap: 56px !important;
}

.k3-wrap{
  margin: 90px auto !important;
}

.cta-section{
  margin-top: 84px !important;
}

/* 10) Scrollytelling visuell komplett deaktivieren */
